class Solution:
    def maxFrequency(self, nums, k):
        nums.sort()
        left = 0
        window = 0
        best = 1
        for right in range(len(nums)):
            window += nums[right]
            while nums[right] * (right - left + 1) > window + k:
                window -= nums[left]
                left += 1
            best = max(best, right - left + 1)
        return best

