var maxFrequency = function(nums, k) {
    nums.sort((a, b) => a - b);
    let left = 0, window = 0, best = 1;
    for (let right = 0; right < nums.length; right++) {
        window += nums[right];
        while (nums[right] * (right - left + 1) > window + k) {
            window -= nums[left];
            left++;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
